// figma-import-plugin.js
// Figma の Plugins > Development > Open console に貼り付けて実行してください。
// 3つのフレーム (1440×900) が横並びで作成されます。

(async () => {
  const frames = [];

  const IMG_LOGIN = "data:image/png;base64,";
const IMG_REGISTER = "data:image/png;base64,";
const IMG_MYPAGE = "data:image/png;base64,";


  // 01_ログイン
  {
    const frame = figma.createFrame();
    frame.name = "01_ログイン";
    frame.resize(1440, 900);
    frame.x = 0;
    frame.y = 0;
    const imgData_login = IMG_LOGIN.replace(/^data:image\/png;base64,/, "");
    const bytes_login = Uint8Array.from(atob(imgData_login), c => c.charCodeAt(0));
    const img_login = figma.createImage(bytes_login);
    frame.fills = [{ type: "IMAGE", scaleMode: "FILL", imageHash: img_login.hash }];
    frames.push(frame);
  }

  // 02_新規登録
  {
    const frame = figma.createFrame();
    frame.name = "02_新規登録";
    frame.resize(1440, 900);
    frame.x = 1540;
    frame.y = 0;
    const imgData_register = IMG_REGISTER.replace(/^data:image\/png;base64,/, "");
    const bytes_register = Uint8Array.from(atob(imgData_register), c => c.charCodeAt(0));
    const img_register = figma.createImage(bytes_register);
    frame.fills = [{ type: "IMAGE", scaleMode: "FILL", imageHash: img_register.hash }];
    frames.push(frame);
  }

  // 03_マイページ
  {
    const frame = figma.createFrame();
    frame.name = "03_マイページ";
    frame.resize(1440, 900);
    frame.x = 3080;
    frame.y = 0;
    const imgData_mypage = IMG_MYPAGE.replace(/^data:image\/png;base64,/, "");
    const bytes_mypage = Uint8Array.from(atob(imgData_mypage), c => c.charCodeAt(0));
    const img_mypage = figma.createImage(bytes_mypage);
    frame.fills = [{ type: "IMAGE", scaleMode: "FILL", imageHash: img_mypage.hash }];
    frames.push(frame);
  }

  figma.currentPage.selection = frames;
  figma.viewport.scrollAndZoomIntoView(frames);
  figma.closePlugin("✅ WeightTracker 3画面をFigmaに追加しました！");
})();
